code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let k, s;
rl.on('line', (input) => {
    if (!k) {
        k = parseInt(input);
    } else {
        s = input;
        for (let i = 0; i < k; i++) {
            process.stdout.write(s);
        }
        rl.close();
    }
});
